import { Component } from '@angular/core';
import { CdbService } from '../../services/cdb.service';
import { CdbCalculationResult } from '../../models/cdb.model';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

@Component({
  selector: 'app-cdb-calculator',
  templateUrl: './cdb-calculator.component.html',
  styleUrls: ['./cdb-calculator.component.scss']
})
export class CdbCalculatorComponent {
  calculationForm: FormGroup;
  result: CdbCalculationResult | null = null;
  isLoading = false;
  errorMessage: string | null = null;

  constructor(
    private readonly fb: FormBuilder,
    private readonly cdbService: CdbService
  ) {
    this.calculationForm = this.fb.group({
      initialValue: [null, [Validators.required, Validators.min(0.01)]],
      months: [null, [Validators.required, Validators.min(2), Validators.pattern('^[0-9]+$')]]
    });
  }

  get initialValueControl() {
    return this.calculationForm.get('initialValue');
  }

  get monthsControl() {
    return this.calculationForm.get('months');
  }

  onSubmit(): void {
    if (this.calculationForm.invalid) {
      this.calculationForm.markAllAsTouched();
      return;
    }

    this.isLoading = true;
    this.errorMessage = null;
    this.result = null;

    const { initialValue, months } = this.calculationForm.value as { initialValue: number; months: number };

    this.cdbService.calculate({ initialValue, months }).subscribe({
      next: (data) => {
        this.result = data;
        this.isLoading = false;
      },
      error: () => {
        this.errorMessage = 'Ocorreu um erro ao calcular. Verifique os dados e tente novamente.';
        this.isLoading = false;
      }
    });
  }

  onReset(): void {
    this.calculationForm.reset();
    this.result = null;
    this.errorMessage = null;
  }
}
<div class="calculator-wrapper">
  <header class="calculator-header">
    <div class="logo-mark">CDB</div>
    <h1>Simulador de Investimento</h1>
    <p class="subtitle">Calcule o rendimento bruto e líquido do seu CDB</p>
  </header>

  <main class="calculator-card">
    <form [formGroup]="calculationForm" (ngSubmit)="onSubmit()" novalidate>
      <div class="field-group">
        <label for="initialValue" class="field-label">
          <span class="label-text">Valor Inicial</span>
          <span class="label-hint">R$</span>
        </label>
        <input
          id="initialValue"
          type="number"
          formControlName="initialValue"
          class="field-input"
          [class.field-input--error]="initialValueControl?.invalid && initialValueControl?.touched"
          placeholder="Ex: 1000,00"
          step="0.01"
          min="0.01"
        />
        <span
          class="field-error"
          *ngIf="initialValueControl?.invalid && initialValueControl?.touched"
        >
          <ng-container *ngIf="initialValueControl?.errors?.['required']">
            Informe o valor inicial.
          </ng-container>
          <ng-container *ngIf="initialValueControl?.errors?.['min']">
            O valor deve ser positivo.
          </ng-container>
        </span>
      </div>

      <div class="field-group">
        <label for="months" class="field-label">
          <span class="label-text">Prazo</span>
          <span class="label-hint">meses</span>
        </label>
        <input
          id="months"
          type="number"
          formControlName="months"
          class="field-input"
          [class.field-input--error]="monthsControl?.invalid && monthsControl?.touched"
          placeholder="Ex: 12"
          step="1"
          min="2"
        />
        <span
          class="field-error"
          *ngIf="monthsControl?.invalid && monthsControl?.touched"
        >
          <ng-container *ngIf="monthsControl?.errors?.['required']">
            Informe o prazo em meses.
          </ng-container>
          <ng-container *ngIf="monthsControl?.errors?.['min']">
            O prazo deve ser maior que 1 mês.
          </ng-container>
          <ng-container *ngIf="monthsControl?.errors?.['pattern']">
            Informe um número inteiro de meses.
          </ng-container>
        </span>
      </div>

      <div class="actions">
        <button
          type="submit"
          class="btn btn--primary"
          [disabled]="isLoading"
        >
          <span class="spinner" *ngIf="isLoading"></span>
          {{ isLoading ? 'Calculando...' : 'Calcular Rendimento' }}
        </button>
        <button
          type="button"
          class="btn btn--ghost"
          (click)="onReset()"
        >
          Limpar
        </button>
      </div>
    </form>

    <div class="alert alert--error" role="alert" *ngIf="errorMessage">
      <span class="alert-icon">⚠</span>
      {{ errorMessage }}
    </div>

    <section class="result-section" aria-live="polite" *ngIf="result">
      <div class="result-divider">
        <span>Resultado da Simulação</span>
      </div>
      <div class="result-grid">
        <div class="result-card result-card--gross">
          <div class="result-label">Valor Bruto</div>
          <div class="result-value">
            {{ result.grossValue | currency:'BRL':'symbol':'1.2-2':'pt-BR' }}
          </div>
          <div class="result-note">Antes do imposto de renda</div>
        </div>
        <div class="result-card result-card--net">
          <div class="result-label">Valor Líquido</div>
          <div class="result-value">
            {{ result.netValue | currency:'BRL':'symbol':'1.2-2':'pt-BR' }}
          </div>
          <div class="result-note">Após dedução do IR</div>
        </div>
      </div>
      <p class="result-disclaimer">
        Simulação baseada em CDI = 0,9% a.m. e TB = 108%
      </p>
    </section>
  </main>

  <footer class="calculator-footer">
    <p>Taxas de IR: até 6m 22,5% · até 12m 20% · até 24m 17,5% · acima de 24m 15%</p>
  </footer>
</div>
